CREATE TRIGGER LG_ACCDISTLINE_DEL_524_01 ON LG_524_01_ACCDISTDETLN
FOR DELETE
AS
DECLARE @DT     DATETIME
DECLARE @MONTH          SMALLINT
DECLARE @YEAR          SMALLINT
DECLARE @SIGN  SMALLINT
DECLARE @ACCFICHEREF    INT
DECLARE @ACCOUNTREF INT
DECLARE @CENTERREF      INT
DECLARE @TRCODE  SMALLINT
DECLARE @ACCOUNTCODE    VARCHAR(100)
DECLARE @DEBIT  FLOAT
DECLARE @CREDIT   FLOAT
DECLARE @EMUDEBIT       FLOAT
DECLARE @EMUCREDIT  FLOAT
DECLARE @CANCELLED SMALLINT
DECLARE @REPORTNET FLOAT
DECLARE @INFIDX         FLOAT
DECLARE @NOTINFLATED    INT
DECLARE @NOTCALCULATED  INT
DECLARE @AMNT  FLOAT
DECLARE @COEF  SMALLINT
DECLARE @BRANCH  SMALLINT
DECLARE @DEPARTMENT SMALLINT
DECLARE @STATUS   SMALLINT
DECLARE @TRNET          FLOAT
DECLARE @TRCURR         SMALLINT
SELECT @DT          = D.DATE_,
       @MONTH       = D.MONTH_,
       @YEAR        = D.YEAR_,
       @SIGN        = D.TSIGN,
       @ACCFICHEREF = D.ACCFICHEREF,
       @ACCOUNTREF  = 0,
       @CENTERREF   = D.CENTERREF,
       @TRCODE      = 0,
       @ACCOUNTCODE = '',
       @DEBIT       = (CASE D.TSIGN WHEN 0 THEN  D.CREDEBNET ELSE 0 END ),
       @CREDIT      = (CASE D.TSIGN WHEN 1 THEN  D.CREDEBNET ELSE 0 END ),
       @EMUDEBIT    = (CASE D.TSIGN WHEN 0 THEN  D.EMUCREDEBNET  ELSE 0 END),
       @EMUCREDIT   = (CASE D.TSIGN WHEN 1 THEN  D.EMUCREDEBNET  ELSE 0 END),
       @CANCELLED   = D.CANCELLED ,
       @REPORTNET   = D.REPORTNET,
       @INFIDX        = 0,
       @NOTINFLATED   = 0,
       @NOTCALCULATED = 0,
       @AMNT        = 0,
       @BRANCH      = D.BRANCH,
       @DEPARTMENT  = D.DEPARTMENT,
       @STATUS      = D.STATUS,
       @TRNET       = D.TRNET,
       @TRCURR      = D.TRCURR FROM DELETED D
SELECT @TRCODE=TRCODE  FROM LG_524_01_EMFICHE WHERE LOGICALREF=@ACCFICHEREF
EXECUTE LG_UPDATE_EMTRANS_524_01 @DT, @SIGN, @ACCOUNTREF, @CENTERREF, @TRCODE, @ACCOUNTCODE, @DEBIT, @CREDIT, @EMUDEBIT, @EMUCREDIT, @CANCELLED, @REPORTNET, @AMNT, -1
        , @INFIDX, @NOTINFLATED, @NOTCALCULATED, @BRANCH, @DEPARTMENT, @STATUS, 0, 0, 0
        , @MONTH, @YEAR, @TRNET, @TRCURR
